      module: text("module").notNull(),
      // clients, campaigns, tasks, invoices, reports, settings, etc.
      canView: boolean("can_view").default(false),
      canCreate: boolean("can_create").default(false),
      canEdit: boolean("can_edit").default(false),
      canDelete: boolean("can_delete").default(false),
      canManage: boolean("can_manage").default(false),
      // for settings and admin functions
      canExport: boolean("can_export").default(false),
      // export data permissions
      canImport: boolean("can_import").default(false),
      // import data permissions
      // Data access level - CRM best practice for data segmentation
      dataAccessLevel: text("data_access_level").notNull().default("own"),
      // own, team, department, all
      // Field-level restrictions for sensitive data
      restrictedFields: text("restricted_fields").array(),
