      // {email, name, self} - organizer info
      organizerEmail: text("organizer_email"),
      // Just the email for quick lookup
      // Sync metadata
      etag: text("etag"),
      // For change detection
      lastModified: timestamp("last_modified"),
      // Google's updated timestamp
      syncedAt: timestamp("synced_at").defaultNow(),
      createdAt: timestamp("created_at").defaultNow(),
      updatedAt: timestamp("updated_at").defaultNow(),
      // Flags
      isRecurring: boolean("is_recurring").default(false),
      // Flag instead of full recurrence data
      createdInAgencyBoost: boolean("created_in_agency_flow").default(false),
      // Track origin for two-way sync
      // Appointment status for time tracking
      appointmentStatus: text("appointment_status").default("confirmed"),
      // confirmed, showed, no_show, cancelled
      timeEntryCreated: boolean("time_entry_created").default(false)
