import { eq, inArray, sql as sql2 } from "drizzle-orm";
async function getGoogleCalendarEventsForView(req, res) {
  try {
    const currentUserId2 = req.session?.userId;
    const { userIds } = req.query;
    console.log("[GoogleCalendarEvents] Request received:", {
      currentUserId: currentUserId2,
      userIds,
      queryParams: req.query
    });
    if (!currentUserId2) {
      return res.status(401).json({ error: "Not authenticated" });
    }
    let events = [];
    if (userIds && typeof userIds === "string") {
      const userIdList = userIds.split(",").filter((id) => id.trim());
      const currentStaff = await db.select().from(staff).where(eq(staff.id, currentUserId2));
      const currentUserOrgId = currentStaff[0]?.organizationId;
      const selectedStaff = await db.select().from(staff).where(inArray(staff.id, userIdList));
      const eventsPromises = userIdList.map(async (userId2) => {
        const userStaff = selectedStaff.find((s) => s.id === userId2);
        const isSameOrg = userStaff?.organizationId === currentUserOrgId;
        const isCurrentUser = userId2 === currentUserId2;
        console.log("[GoogleCalendarEvents] Processing user:", {
          userId: userId2,
          isCurrentUser,
          isSameOrg,
          userStaff: userStaff?.email
        });
        const userEvents = await db.select({
          id: calendarEvents.id,
          googleEventId: calendarEvents.googleEventId,
          connectionId: calendarEvents.connectionId,
          // Show full details for own events or same org, otherwise show "Busy"
          title: isCurrentUser || isSameOrg ? sql2`COALESCE(${calendarEvents.summary}, 'Untitled Event')`.as("title") : sql2`'Busy'`.as("title"),
          description: isCurrentUser || isSameOrg ? calendarEvents.description : sql2`''`.as("description"),
          startTime: calendarEvents.startTime,
          endTime: calendarEvents.endTime,
          location: isCurrentUser || isSameOrg ? calendarEvents.location : sql2`''`.as("location"),
          // IMPORTANT: Only show meeting link for own events (privacy/security)
          meetingLink: isCurrentUser ? calendarEvents.googleHangoutLink : sql2`null`.as("meetingLink"),
          googleHtmlLink: isCurrentUser ? calendarEvents.googleHtmlLink : sql2`null`.as("googleHtmlLink"),
          status: calendarEvents.status,
          allDay: calendarEvents.allDay,
          transparency: calendarEvents.transparency,
          organizerEmail: isCurrentUser || isSameOrg ? calendarEvents.organizerEmail : sql2`''`.as("organizerEmail"),
          organizer: isCurrentUser || isSameOrg ? calendarEvents.organizer : sql2`null`.as("organizer"),
          attendees: isCurrentUser || isSameOrg ? calendarEvents.attendees : sql2`'[]'::jsonb`.as("attendees"),
          isRecurring: calendarEvents.isRecurring,
          createdInAgencyBoost: calendarEvents.createdInAgencyBoost,
          appointmentStatus: calendarEvents.appointmentStatus,
          timeEntryCreated: calendarEvents.timeEntryCreated,
          // CRITICAL: Use the connection's userId (which is the staff ID who owns this calendar)
          userId: calendarConnections.userId,
          assignedTo: calendarConnections.userId
        }).from(calendarEvents).innerJoin(calendarConnections, eq(calendarEvents.connectionId, calendarConnections.id)).where(eq(calendarConnections.userId, userId2));
        console.log("[GoogleCalendarEvents] Found events for user:", {
          userId: userId2,
          eventCount: userEvents.length,
          firstEvent: userEvents[0]?.title
        });
        return userEvents;
      });
      const allEvents = await Promise.all(eventsPromises);
      events = allEvents.flat();
    } else {
      const userEvents = await db.select({
        id: calendarEvents.id,
        googleEventId: calendarEvents.googleEventId,
        connectionId: calendarEvents.connectionId,
        title: sql2`COALESCE(${calendarEvents.summary}, 'Untitled Event')`.as("title"),
        description: calendarEvents.description,
        startTime: calendarEvents.startTime,
        endTime: calendarEvents.endTime,
        location: calendarEvents.location,
        meetingLink: calendarEvents.googleHangoutLink,
        googleHtmlLink: calendarEvents.googleHtmlLink,
        status: calendarEvents.status,
        allDay: calendarEvents.allDay,
        transparency: calendarEvents.transparency,
        organizerEmail: calendarEvents.organizerEmail,
        organizer: calendarEvents.organizer,
        attendees: calendarEvents.attendees,
        isRecurring: calendarEvents.isRecurring,
        createdInAgencyBoost: calendarEvents.createdInAgencyBoost,
        appointmentStatus: calendarEvents.appointmentStatus,
        timeEntryCreated: calendarEvents.timeEntryCreated,
        // Include userId and assignedTo
        userId: calendarConnections.userId,
        assignedTo: calendarConnections.userId
      }).from(calendarEvents).innerJoin(calendarConnections, eq(calendarEvents.connectionId, calendarConnections.id)).where(eq(calendarConnections.userId, currentUserId2));
      events = userEvents;
    }
    const transformedEvents = events.map((event) => ({
      ...event,
      // Ensure compatibility with frontend expectations
      bookerName: event.organizerName || "",
      bookerEmail: event.organizerEmail || "",
      bookerPhone: null,
      clientId: null,
      timezone: "UTC",
      customFieldData: null,
      externalEventId: event.googleEventId,
      bookingSource: "google-calendar",
      cancelledAt: null,
      cancelledBy: null,
      cancellationReason: null,
      type: "google"
    }));
    console.log("[GoogleCalendarEvents] Returning events:", {
      totalCount: transformedEvents.length,
      userIds: userIds || "none",
      sampleEvents: transformedEvents.slice(0, 2).map((e) => ({
        title: e.title,
        assignedTo: e.assignedTo,
        userId: e.userId,
        meetingLink: e.meetingLink || "none",
        type: typeof e.assignedTo
      }))
    });
    res.json({ events: transformedEvents });
  } catch (error) {
    console.error("[GoogleCalendarEvents] Error fetching Google Calendar events for calendar view:", error);
    res.status(500).json({ error: "Failed to fetch Google Calendar events", details: error.message });
  }
}

