  app2.put("/api/custom-fields/reorder", requireAuth(), requirePermission("settings", "canManage"), async (req, res) => {
    try {
      const { fieldIds } = req.body;
      if (!Array.isArray(fieldIds)) {
        return res.status(400).json({ message: "fieldIds must be an array" });
      }
      for (let i = 0; i < fieldIds.length; i++) {
        const fieldId = fieldIds[i];
        const newOrder = i + 1;
        await db.update(customFields).set({ order: newOrder }).where(eq20(customFields.id, fieldId));
      }
      res.json({ message: "Field order updated successfully" });
    } catch (error) {
      console.error("Error reordering custom fields:", error);
      res.status(500).json({ message: "Failed to reorder fields" });
    }
  });
