  app2.post("/api/custom-fields", requireAuth(), requirePermission("settings", "canManage"), async (req, res) => {
    try {
      const result = insertCustomFieldSchema.safeParse(req.body);
      if (!result.success) {
        return res.status(400).json({
          error: "Invalid custom field data",
          details: result.error.issues
        });
      }
      const maxOrderResult = await db.select({ maxOrder: sql11`COALESCE(MAX(${customFields.order}), 0)` }).from(customFields);
      const nextOrder = (maxOrderResult[0]?.maxOrder || 0) + 1;
      const [newField] = await db.insert(customFields).values({
        ...result.data,
        order: nextOrder
      }).returning();
      res.status(201).json(newField);
    } catch (error) {
      console.error("Error creating custom field:", error);
      res.status(500).json({ error: "Internal server error" });
    }
  });
