  app2.post("/api/workflows/:id/save-as-template", requireAuth(), requireRole(["Admin", "Manager"]), async (req, res) => {
    try {
      const userId2 = getAuthenticatedUserIdOrFail(req, res);
      if (!userId2) return;
      const [workflow] = await db.select().from(workflows).where(eq20(workflows.id, req.params.id));
      if (!workflow) {
        return res.status(404).json({ message: "Workflow not found" });
      }
      const [existingTemplate] = await db.select().from(workflowTemplates).where(eq20(workflowTemplates.workflowId, req.params.id));
      if (existingTemplate) {
        return res.status(409).json({
          message: "A template already exists for this workflow",
          templateId: existingTemplate.id
        });
      }
      const templateData = {
        name: workflow.name,
        description: workflow.description,
        category: workflow.category || "General",
        // Default to 'General' if workflow has no category
        industry: req.body.industry || null,
        useCase: req.body.useCase || null,
        triggers: workflow.triggers,
        actions: workflow.actions,
        conditions: workflow.conditions,
        settings: workflow.settings,
        isPublic: req.body.isPublic || false,
        tags: req.body.tags || [],
        workflowId: workflow.id,
        // Link template to source workflow with unique constraint
        createdBy: userId2
      };
      const template = await storage2.createWorkflowTemplate(templateData);
      await createAuditLog(
        "created",
        "workflow_template",
        template.id,
        template.name,
        userId2,
        `Saved workflow "${workflow.name}" as template`,
        null,
        { workflowId: workflow.id, templateName: template.name },
        req
      );
      res.status(201).json(template);
    } catch (error) {
      console.error("Error saving workflow as template:", error);
      res.status(500).json({ message: "Failed to save workflow as template" });
    }
  });
