  app2.put("/api/automation-triggers/:id", requireAuth(), requirePermission("workflows", "canEdit"), async (req, res) => {
    try {
      const oldTrigger = await storage2.getAutomationTrigger(req.params.id);
      if (!oldTrigger) {
        return res.status(404).json({ message: "Automation trigger not found" });
      }
      const validatedData = insertAutomationTriggerSchema.partial().parse(req.body);
      const trigger = await storage2.updateAutomationTrigger(req.params.id, validatedData);
      if (!trigger) {
        return res.status(404).json({ message: "Automation trigger not found" });
      }
      const changes = [];
      if (validatedData.name && validatedData.name !== oldTrigger.name) {
        changes.push(`name from "${oldTrigger.name}" to "${validatedData.name}"`);
      }
      if (validatedData.description && validatedData.description !== oldTrigger.description) {
        changes.push(`description updated`);
      }
      if (validatedData.isActive !== void 0 && validatedData.isActive !== oldTrigger.isActive) {
        changes.push(`status ${validatedData.isActive ? "activated" : "deactivated"}`);
      }
      const userId2 = getAuthenticatedUserIdOrFail(req, res);
      if (!userId2) return;
      await createAuditLog(
        "updated",
        "automation_trigger",
        trigger.id,
        trigger.name,
        userId2,
        // SECURE: Use authenticated user ID only
        changes.length > 0 ? `Updated ${changes.join(", ")}` : "Automation trigger updated",
        { name: oldTrigger.name, description: oldTrigger.description, isActive: oldTrigger.isActive },
        { name: trigger.name, description: trigger.description, isActive: trigger.isActive },
        req
      );
      res.json(trigger);
    } catch (error) {
      if (error instanceof z3.ZodError) {
        return res.status(400).json({ message: "Invalid data", errors: error.errors });
      }
      res.status(500).json({ message: "Failed to update automation trigger" });
    }
  });
  app2.delete("/api/automation-triggers/:id", requireAuth(), requirePermission("workflows", "canDelete"), async (req, res) => {
    try {
      const trigger = await storage2.getAutomationTrigger(req.params.id);
      if (!trigger) {
        return res.status(404).json({ message: "Automation trigger not found" });
      }
      const deleted = await storage2.deleteAutomationTrigger(req.params.id);
      if (!deleted) {
        return res.status(404).json({ message: "Automation trigger not found" });
      }
      const userId2 = getAuthenticatedUserIdOrFail(req, res);
      if (!userId2) return;
      await createAuditLog(
        "deleted",
        "automation_trigger",
        req.params.id,
        trigger.name,
        userId2,
        // SECURE: Use authenticated user ID only
        `Automation trigger permanently deleted - ${trigger.name} (${trigger.type})`,
        { name: trigger.name, type: trigger.type, category: trigger.category },
        null,
        req
      );
      res.status(204).send();
    } catch (error) {
      res.status(500).json({ message: "Failed to delete automation trigger" });
    }
  });
