  app2.put("/api/forms/:id", requireAuth(), requirePermission("campaigns", "canEdit"), async (req, res) => {
    try {
      const { fields, ...formData3 } = req.body;
      const allowedFields = ["name", "description", "status", "settings"];
      const cleanFormData = {};
      for (const field of allowedFields) {
        if (formData3[field] !== void 0) {
          cleanFormData[field] = formData3[field];
        }
      }
      const formResult = await db.execute(sql11`
        UPDATE forms 
        SET 
          name = COALESCE(${cleanFormData.name}, name),
          description = COALESCE(${cleanFormData.description}, description),
          status = COALESCE(${cleanFormData.status}, status),
          settings = COALESCE(${cleanFormData.settings ? JSON.stringify(cleanFormData.settings) : null}, settings),
          updated_by = ${userId},
          updated_at = NOW()
        WHERE id = ${req.params.id}
        RETURNING *
      `);
      if (!formResult.rows || formResult.rows.length === 0) {
        return res.status(404).json({ message: "Form not found" });
      }
      const form = formResult.rows[0];
      if (fields && Array.isArray(fields)) {
        const existingFields = await db.select().from(formFields).where(eq20(formFields.formId, req.params.id));
        const realFieldIds = fields.map((f) => f.id).filter((id) => id && !id.startsWith("temp-"));
        for (const existingField of existingFields) {
          if (!realFieldIds.includes(existingField.id)) {
            await db.delete(formFields).where(eq20(formFields.id, existingField.id));
          }
        }
        for (let i = 0; i < fields.length; i++) {
          const field = fields[i];
          if (field.id && !field.id.startsWith("temp-")) {
            const { createdAt, ...fieldData } = field;
            await db.update(formFields).set({ ...fieldData, order: i }).where(eq20(formFields.id, field.id));
          } else {
            const { createdAt, id, ...fieldData } = field;
            await db.insert(formFields).values({
              ...fieldData,
              formId: req.params.id,
              order: i
            });
          }
        }
      }
      res.json(form);
    } catch (error) {
      console.error("Error updating form:", error);
      res.status(500).json({ message: "Failed to update form" });
    }
  });
