async function setupAuth(app2) {
  app2.set("trust proxy", 1);
  app2.use(getSession());
  console.log("\u2705 Google OAuth initialized");
  app2.get("/api/login", (req, res) => {
    try {
      if (req.session) {
        delete req.session.userId;
        delete req.session.user;
        delete req.session.impersonatedUserId;
        delete req.session.originalAdminUserId;
      }
      const oauth2Client = createOAuth2Client2(req);
      const redirectUri = getRedirectUri2(req);
      console.log("\u{1F510} Using redirect URI:", redirectUri);
      const authUrl = oauth2Client.generateAuthUrl({
        access_type: "offline",
        scope: [
          "https://www.googleapis.com/auth/userinfo.email",
          "https://www.googleapis.com/auth/userinfo.profile",
          "openid"
        ],
        prompt: "select_account",
        // Always show account selector
        include_granted_scopes: true
      });
      console.log("\u{1F510} Starting Google OAuth flow - redirecting to:", authUrl.substring(0, 100) + "...");
      res.redirect(authUrl);
    } catch (error) {
      console.error("Error starting OAuth flow:", error);
      res.redirect("/login?error=oauth_init_failed");
    }
  });
  app2.get("/api/callback", async (req, res) => {
    console.log("\u{1F4E5} OAuth callback received:", {
      query: req.query,
      url: req.url,
      originalUrl: req.originalUrl,
      host: req.hostname
    });
    const { code, error, error_description } = req.query;
    if (error) {
      console.error("Google OAuth error:", error, error_description);
      return res.redirect(`/login?error=google_denied&details=${encodeURIComponent(String(error_description || error))}`);
    }
    if (!code || typeof code !== "string") {
      console.error("No authorization code received. Query params:", JSON.stringify(req.query));
      return res.redirect("/login?error=no_code");
    }
    try {
      console.log("\u{1F504} Exchanging authorization code for tokens...");
      const oauth2Client = createOAuth2Client2(req);
      console.log("\u{1F504} Using redirect URI for token exchange:", getRedirectUri2(req));
      const { tokens } = await oauth2Client.getToken(code);
      console.log("\u2705 Tokens received:", {
        hasAccessToken: !!tokens.access_token,
        hasRefreshToken: !!tokens.refresh_token,
        expiryDate: tokens.expiry_date
      });
      oauth2Client.setCredentials(tokens);
      const userInfoResponse = await fetch(
        "https://www.googleapis.com/oauth2/v3/userinfo",
        {
          headers: {
            Authorization: `Bearer ${tokens.access_token}`
          }
        }
      );
      if (!userInfoResponse.ok) {
        throw new Error("Failed to fetch user info from Google");
      }
      const userInfo = await userInfoResponse.json();
      console.log("\u{1F511} Google user info received:", JSON.stringify({
        sub: userInfo.sub,
        email: userInfo.email,
        name: userInfo.name,
        given_name: userInfo.given_name,
        family_name: userInfo.family_name
      }));
      const staffMember = await upsertStaffFromGoogleProfile({
        sub: userInfo.sub,
        email: userInfo.email,
        given_name: userInfo.given_name,
        family_name: userInfo.family_name,
        picture: userInfo.picture
      });
      req.session.userId = staffMember.id;
      req.session.user = {
        id: staffMember.id,
        staffId: staffMember.id,
        email: userInfo.email,
        accessToken: tokens.access_token,
        refreshToken: tokens.refresh_token,
        expiresAt: tokens.expiry_date
      };
      req.session.save((err) => {
        if (err) {
          console.error("Session save error:", err);
          return res.redirect("/login?error=session_failed");
        }
        console.log("\u2705 Authentication successful for:", userInfo.email, "-> staffId:", staffMember.id);
        res.redirect("/dashboard");
      });
    } catch (error2) {
      console.error("Google OAuth callback error:", error2.message);
      console.error("Full error:", error2);
      if (error2.response?.data) {
        console.error("Error response data:", error2.response.data);
      }
      let errorCode = "auth_failed";
      if (error2.message?.includes("deactivated")) {
        errorCode = "account_deactivated";
      } else if (error2.message?.includes("different Google account")) {
        errorCode = "email_linked_to_different_account";
      } else if (error2.message?.includes("Email is required")) {
        errorCode = "no_email_provided";
      }
      res.redirect(`/login?error=${errorCode}&details=${encodeURIComponent(error2.message || "Authentication failed")}`);
    }
  });
  app2.get("/api/link-gmail", (req, res) => {
    try {
      if (!req.session.userId) {
        return res.redirect("/login?error=login_required");
      }
      const oauth2Client = createOAuth2Client2(req);
      req.session.linkingStaffId = req.session.userId;
      const redirectUri = getRedirectUri2(req).replace("/callback", "/link-gmail-callback");
      const actualClient = new OAuth2Client2(
        GOOGLE_CLIENT_ID2,
        GOOGLE_CLIENT_SECRET2,
        redirectUri
      );
      const authUrl = actualClient.generateAuthUrl({
        access_type: "offline",
        scope: [
          "https://www.googleapis.com/auth/userinfo.email",
          "https://www.googleapis.com/auth/userinfo.profile",
          "openid"
        ],
        prompt: "select_account",
        include_granted_scopes: true
      });
      console.log("\u{1F517} Starting Gmail linking flow for staff:", req.session.userId);
      res.redirect(authUrl);
    } catch (error) {
      console.error("Error starting link Gmail flow:", error);
      res.redirect("/settings/staff/" + req.session.userId + "?error=link_failed");
    }
  });
  app2.get("/api/link-gmail-callback", async (req, res) => {
    try {
      const code = req.query.code;
      const staffIdToLink = req.session.linkingStaffId;
      const currentUserId2 = req.session.userId;
      if (!code) {
        throw new Error("No authorization code received");
      }
      if (!staffIdToLink) {
        throw new Error("No staff ID found for linking. Please try again.");
      }
      if (staffIdToLink !== currentUserId2) {
        console.error("Security: Attempted to link Gmail to different staff ID", {
          staffIdToLink,
          currentUserId: currentUserId2
        });
        delete req.session.linkingStaffId;
        throw new Error("You can only link Gmail accounts to your own profile.");
      }
      const redirectUri = getRedirectUri2(req).replace("/callback", "/link-gmail-callback");
      const oauth2Client = new OAuth2Client2(
        GOOGLE_CLIENT_ID2,
        GOOGLE_CLIENT_SECRET2,
        redirectUri
      );
      const { tokens } = await oauth2Client.getToken(code);
      oauth2Client.setCredentials(tokens);
      const userInfoResponse = await fetch(
        "https://www.googleapis.com/oauth2/v3/userinfo",
        {
          headers: { Authorization: `Bearer ${tokens.access_token}` }
        }
      );
      if (!userInfoResponse.ok) {
        throw new Error("Failed to fetch user info from Google");
      }
      const userInfo = await userInfoResponse.json();
      const normalizedEmail = userInfo.email.toLowerCase().trim();
      const googleSub = userInfo.sub;
      console.log("\u{1F517} Linking Gmail:", normalizedEmail, "to staff:", staffIdToLink);
      const existingLink = await db.select().from(staffLinkedEmails).where(sql12`LOWER(${staffLinkedEmails.email}) = ${normalizedEmail}`).limit(1);
      if (existingLink.length > 0) {
        if (existingLink[0].staffId === staffIdToLink) {
          delete req.session.linkingStaffId;
          return res.redirect("/settings/staff/" + staffIdToLink + "?message=email_already_linked");
        } else {
          delete req.session.linkingStaffId;
          return res.redirect("/settings/staff/" + staffIdToLink + "?error=email_linked_to_other_account");
        }
      }
      const existingBySub = await db.select().from(staffLinkedEmails).where(eq21(staffLinkedEmails.googleSub, googleSub)).limit(1);
      if (existingBySub.length > 0 && existingBySub[0].staffId !== staffIdToLink) {
        delete req.session.linkingStaffId;
        return res.redirect("/settings/staff/" + staffIdToLink + "?error=google_account_linked_to_other_staff");
      }
      await db.insert(staffLinkedEmails).values({
        staffId: staffIdToLink,
        email: normalizedEmail,
        googleSub,
        isPrimary: false
      });
      console.log("\u2705 Successfully linked Gmail:", normalizedEmail, "to staff:", staffIdToLink);
      delete req.session.linkingStaffId;
      res.redirect("/settings/staff/" + staffIdToLink + "?message=email_linked_successfully");
    } catch (error) {
      console.error("Error in link Gmail callback:", error);
      const staffId = req.session.linkingStaffId;
      delete req.session.linkingStaffId;
      res.redirect("/settings/staff/" + (staffId || "") + "?error=link_failed&details=" + encodeURIComponent(error.message));
    }
  });
  app2.get("/api/logout", (req, res) => {
    const redirectUrl = `https://${req.hostname}/login`;
    if (req.session) {
      req.session.destroy((err) => {
        if (err) {
          console.error("Session destroy error:", err);
        }
        res.clearCookie("connect.sid", {
          path: "/",
          httpOnly: true,
          secure: true,
          sameSite: "none"
        });
        console.log("\u2705 Session destroyed, redirecting to login");
        res.redirect(redirectUrl);
      });
    } else {
      res.redirect(redirectUrl);
    }
  });
}

