router.post("/sync", async (req, res) => {
  if (!req.session?.userId) {
    return res.status(401).json({ error: "Not authenticated" });
  }
  try {
    const connections = await db.select().from(calendarConnections).where(eq23(calendarConnections.userId, req.session.userId));
    if (connections.length === 0) {
      return res.status(400).json({ error: "No Google Calendar connected" });
    }
    const syncState = await db.query.calendarSyncState.findFirst({
      where: eq23(calendarSyncState.connectionId, connections[0].id)
    });
    if (syncState?.lastSyncStatus === "in_progress") {
      const timeSinceStart = Date.now() - (syncState.lastSyncStarted?.getTime() || 0);
      if (timeSinceStart < 12e4) {
        return res.json({
          success: true,
          message: "Sync already in progress",
          status: "in_progress"
        });
      }
    }
    const { syncUserCalendar: syncUserCalendar2 } = await Promise.resolve().then(() => (init_googleCalendarSync(), googleCalendarSync_exports));
    syncUserCalendar2(req.session.userId, "primary").then((result) => {
      console.log(`[Sync Complete] User ${req.session?.userId}: ${result.eventsCreated} created, ${result.eventsUpdated} updated, ${result.eventsDeleted} deleted`);
    }).catch((error) => {
      console.error("[Sync Error]", error);
    });
    res.json({
      success: true,
      message: "Sync started. This may take a few moments for large calendars.",
      status: "started"
    });
  } catch (error) {
    console.error("Sync error details:", {
      error: error instanceof Error ? {
        message: error.message,
        stack: error.stack,
        name: error.name
      } : error,
      userId: req.session?.userId
    });
    res.status(500).json({ error: error instanceof Error ? error.message : "Failed to start sync" });
  }
});
router.post("/auto-sync", async (req, res) => {
  if (!req.session?.userId) {
    return res.status(401).json({ error: "Not authenticated" });
  }
  try {
    const STALE_THRESHOLD_MS = 60 * 1e3;
    const connections = await db.select().from(calendarConnections).where(and20(
      eq23(calendarConnections.userId, req.session.userId),
      eq23(calendarConnections.syncEnabled, true)
    ));
    if (connections.length === 0) {
      return res.json({
        synced: false,
        reason: "no_connection",
        message: "No Google Calendar connected"
      });
    }
    const connection = connections[0];
    const lastSyncedAt = connection.lastSyncedAt?.getTime() || 0;
    const timeSinceSync = Date.now() - lastSyncedAt;
    const syncState = await db.query.calendarSyncState.findFirst({
      where: eq23(calendarSyncState.connectionId, connection.id)
    });
    if (syncState?.lastSyncStatus === "in_progress") {
      const timeSinceStart = Date.now() - (syncState.lastSyncStarted?.getTime() || 0);
      if (timeSinceStart < 12e4) {
        return res.json({
          synced: false,
          reason: "in_progress",
          message: "Sync already in progress"
        });
      }
    }
    if (timeSinceSync < STALE_THRESHOLD_MS) {
      return res.json({
        synced: false,
        reason: "recent",
        lastSyncedAt: connection.lastSyncedAt,
        message: "Data is recent, no sync needed"
      });
    }
    const { syncUserCalendar: syncUserCalendar2 } = await Promise.resolve().then(() => (init_googleCalendarSync(), googleCalendarSync_exports));
    syncUserCalendar2(req.session.userId, "primary").then((result) => {
      console.log(`[Auto-Sync Complete] User ${req.session?.userId}: ${result.eventsCreated} created, ${result.eventsUpdated} updated, ${result.eventsDeleted} deleted`);
    }).catch((error) => {
      console.error("[Auto-Sync Error]", error);
    });
    res.json({
      synced: true,
      reason: "stale",
      message: "Sync started in background"
    });
  } catch (error) {
    console.error("Auto-sync error:", error);
    res.status(500).json({ error: "Failed to trigger auto-sync" });
  }
});
